import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  Wallet, ShoppingBag, CreditCard, 
  LayoutDashboard, Plus, TrendingUp, ChevronRight,
  User as UserIcon, Users, X, Calendar, History, ChevronDown
} from 'lucide-react';
import { Link } from 'react-router-dom';
import '../styles/Menu.css';
import '../styles/Cartoes.css';

const Menu = () => {
  const [resumo, setResumo] = useState({ total: 0, quantidade: 0 });
  const [gastosPorUsuario, setGastosPorUsuario] = useState([]);
  const [historicoMensal, setHistoricoMensal] = useState([]);
  const [perfil, setPerfil] = useState({ nome: 'Usuário', tipo: 'comum' });
  const [loading, setLoading] = useState(true);
  const [showModalHistorico, setShowModalHistorico] = useState(false);

  useEffect(() => {
    buscarDados();
  }, []);

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  async function buscarDados() {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: perfilData } = await supabase.from('profiles').select('*').eq('id', user.id).single();
      const { data: todosPerfis } = await supabase.from('profiles').select('id, nome');
      const { data: cartoes } = await supabase.from('cartoes').select('nome, dia_fechamento');
      
      const isMaster = user.email === 'gleidson.fig@gmail.com';
      const tipoFinal = isMaster ? 'proprietario' : (perfilData?.tipo_usuario || 'comum');
      if (perfilData) setPerfil({ nome: perfilData.nome.split(' ')[0], tipo: tipoFinal });

      const mapaNomes = {};
      todosPerfis?.forEach(p => mapaNomes[p.id] = p.nome.split(' ')[0]);

      let query = supabase.from('compras').select('*');
      if (tipoFinal !== 'proprietario') query = query.eq('user_id', user.id);
      const { data: todasCompras } = await query;

      const agora = new Date();
      const mesAtualChave = `${agora.getFullYear()}-${String(agora.getMonth() + 1).padStart(2, '0')}`;
      
      const mapaHistorico = {}; 
      let contadorItensFaturadosNoMes = 0; // Variável corrigida para contar itens reais do mês
      
      todasCompras?.forEach(item => {
        const numP = parseInt(item.num_parcelas) || 1;
        const [anoC, mesC, diaC] = item.data_compra.split('-').map(Number);
        const valorP = parseFloat((parseFloat(item.valor_total) / numP).toFixed(2));
        const nomeResponsavel = mapaNomes[item.user_id] || 'Outros';
        
        let delayMes = 0;
        // Lógica de fechamento de cartão idêntica à Listagem
        if (item.forma_pagamento === 'Crédito' && item.cartao !== 'À Vista') {
          const infoCartao = cartoes?.find(c => c.nome === item.cartao);
          if (infoCartao && diaC > infoCartao.dia_fechamento) delayMes = 1;
        }

        for (let i = 0; i < numP; i++) {
          const dtP = new Date(anoC, (mesC - 1) + delayMes + i, 1);
          const chaveMes = `${dtP.getFullYear()}-${String(dtP.getMonth() + 1).padStart(2, '0')}`;
          
          if (!mapaHistorico[chaveMes]) {
            mapaHistorico[chaveMes] = { total: 0, porUsuario: {} };
          }

          mapaHistorico[chaveMes].total += valorP;
          mapaHistorico[chaveMes].porUsuario[nomeResponsavel] = (mapaHistorico[chaveMes].porUsuario[nomeResponsavel] || 0) + valorP;

          // Incrementa a contagem se a parcela (ou compra à vista) cair no mês atual
          if (chaveMes === mesAtualChave) {
            contadorItensFaturadosNoMes++;
          }
        }
      });

      const listaHistorico = Object.keys(mapaHistorico)
        .map(chave => ({ chave, ...mapaHistorico[chave] }))
        .sort((a, b) => b.chave.localeCompare(a.chave));

      const dadosMesAtual = mapaHistorico[mesAtualChave] || { total: 0, porUsuario: {} };

      setHistoricoMensal(listaHistorico);
      setGastosPorUsuario(Object.keys(dadosMesAtual.porUsuario).map(n => ({ nome: n, valor: dadosMesAtual.porUsuario[n] })));
      
      setResumo({ 
        total: dadosMesAtual.total, 
        quantidade: contadorItensFaturadosNoMes 
      });

    } catch (err) {
      console.error("Erro ao buscar dados do menu:", err);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="menu-container fade-in">
      <header className="menu-header">
        <div>
          <span className="header-subtitle">Visão Geral</span>
          <h1 className="header-title">Olá, {perfil.nome} 👋</h1>
        </div>
        <div className="trending-icon-box">
          <TrendingUp color="#4361ee" size={28} />
        </div>
      </header>

      <div className="main-card" onClick={() => setShowModalHistorico(true)} style={{ cursor: 'pointer' }}>
        <div className="main-card-content">
          <div className="card-label-row">
            {perfil.tipo === 'proprietario' ? <Users size={18} /> : <UserIcon size={18} />}
            <span>{perfil.tipo === 'proprietario' ? 'Dívidas Totais do Mês' : 'Minha Dívida este Mês'}</span>
            <History size={14} style={{ marginLeft: 'auto', opacity: 0.6 }} />
          </div>

          <h2 className="total-value">{formatMoney(resumo.total)}</h2>

          {perfil.tipo === 'proprietario' && (
            <div className="mini-cards-container">
              {gastosPorUsuario.map((g, i) => (
                <div key={i} className="mini-card">
                  <span className="mini-card-label">{g.nome}</span>
                  <span className="mini-card-value">{formatMoney(g.valor)}</span>
                </div>
              ))}
            </div>
          )}

          <div className="pills-row">
            <div className="pill">
              <span className="pill-label">Itens faturados</span>
              <span style={{fontWeight: 800}}>{resumo.quantidade}</span>
            </div>
          </div>
        </div>
        <div className="card-decoration" />
      </div>

      <h3 className="section-title">Ações Rápidas</h3>
      
      <div className="actions-grid">
        <QuickActionLink to="/dashboard" icon={<LayoutDashboard size={26} />} label="Dashboard" sub="Análise" color="#4361ee" />
        {perfil.tipo === 'proprietario' && (
          <QuickActionLink to="/cartoes" icon={<CreditCard size={26} />} label="Cartões" sub="Limites" color="#7209b7" />
        )}
        <QuickActionLink to="/listagem" icon={<ShoppingBag size={26} />} label="Extrato" sub="Histórico" color="#00cc66" />
        {perfil.tipo === 'proprietario' && (
          <QuickActionLink to="/lancamento" icon={<Plus size={26} />} label="Novo" sub="Lançar" color="#fff" isPrimary />
        )}
      </div>

      <Link to="/perfil" style={{ textDecoration: 'none' }}>
        <div className="footer-action">
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
            <div className="footer-icon-box">
              <UserIcon size={20} color="#4361ee" />
            </div>
            <div>
              <span style={{ display: 'block', fontSize: '0.95rem', fontWeight: 800, color: '#0f172a' }}>Perfil</span>
              <span style={{ fontSize: '0.8rem', color: '#64748b' }}>Gerenciar conta</span>
            </div>
          </div>
          <ChevronRight size={20} color="#64748b" />
        </div>
      </Link>

      {/* MODAL DE HISTÓRICO MENSAL */}
      {showModalHistorico && (
        <div className="modal-overlay" onClick={() => setShowModalHistorico(false)}>
          <div className="modal-content fade-in" onClick={e => e.stopPropagation()} style={{ padding: 0, maxWidth: '450px' }}>
            <div className="modal-details-header" style={{ background: '#1e293b', padding: '25px' }}>
               <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <h2 style={{ margin: 0, fontSize: '1.2rem', color: 'white' }}>Histórico de Gastos</h2>
                  <button onClick={() => setShowModalHistorico(false)} className="btn-close-round"><X size={18}/></button>
               </div>
               <p style={{ color: 'rgba(255,255,255,0.7)', margin: '5px 0 0 0', fontSize: '0.85rem' }}>Fechamento mensal detalhado</p>
            </div>

            <div style={{ padding: '15px', maxHeight: '450px', overflowY: 'auto' }}>
              {historicoMensal.map((mesObj, idx) => {
                const [ano, mes] = mesObj.chave.split('-');
                const dataFormatada = new Intl.DateTimeFormat('pt-BR', { month: 'long', year: 'numeric' }).format(new Date(ano, mes - 1));
                const isAtual = new Date().getMonth() === (mes - 1) && new Date().getFullYear() === parseInt(ano);

                return (
                  <div key={idx} style={{ 
                    marginBottom: '12px',
                    background: isAtual ? '#f8fafc' : '#fff',
                    borderRadius: '16px',
                    border: isAtual ? '2px solid #e2e8f0' : '1px solid #f1f5f9',
                    overflow: 'hidden'
                  }}>
                    <div style={{ 
                      display: 'flex', 
                      justifyContent: 'space-between', 
                      padding: '16px', 
                      alignItems: 'center',
                      borderBottom: perfil.tipo === 'proprietario' ? '1px dashed #e2e8f0' : 'none'
                    }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <Calendar size={18} color={isAtual ? '#4361ee' : '#64748b'} />
                        <span style={{ fontWeight: '800', textTransform: 'capitalize', color: '#1e293b' }}>
                          {dataFormatada}
                        </span>
                      </div>
                      <span style={{ fontWeight: '900', color: isAtual ? '#4361ee' : '#0f172a' }}>
                        {formatMoney(mesObj.total)}
                      </span>
                    </div>

                    {perfil.tipo === 'proprietario' && (
                      <div style={{ padding: '12px 16px', background: 'rgba(241, 245, 249, 0.5)', display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(100px, 1fr))', gap: '10px' }}>
                        {Object.entries(mesObj.porUsuario).map(([nome, valor]) => (
                          <div key={nome} style={{ display: 'flex', flexDirection: 'column' }}>
                            <span style={{ fontSize: '0.65rem', fontWeight: '700', color: '#64748b', textTransform: 'uppercase' }}>{nome}</span>
                            <span style={{ fontSize: '0.85rem', fontWeight: '800', color: '#334155' }}>{formatMoney(valor)}</span>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const QuickActionLink = ({ to, icon, label, sub, color, isPrimary }) => (
  <Link to={to} style={{ textDecoration: 'none' }}>
    <div className={`quick-action-card ${isPrimary ? 'primary' : 'secondary'}`}>
      <div className="action-icon-wrapper" style={{ background: isPrimary ? 'rgba(255,255,255,0.2)' : `${color}15`, color: isPrimary ? '#fff' : color }}>
        {icon}
      </div>
      <div>
        <span style={{ display: 'block', fontWeight: 800, fontSize: '1.1rem', color: isPrimary ? '#fff' : '#0f172a' }}>{label}</span>
        <span style={{ fontSize: '0.8rem', fontWeight: 600, color: isPrimary ? 'rgba(255,255,255,0.7)' : '#64748b' }}>{sub}</span>
      </div>
    </div>
  </Link>
);

export default Menu;
